// // This module implements a combinatorial circuit with three inputs (A1, A2) and two data sources (B1 and C1). The output X is determined by the values of A1 and A2: if both are LOW, X outputs the value from B1; if A1 is LOW and A2 is HIGH, X outputs the value from C1; otherwise, X outputs a constant HIGH.
module top_module(
    X ,
    A1,
    A2,
    B1,
    C1
);output X ;
    input  A1;
    input  A2;
    input  B1;
    input  C1;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;

    assign X = ((A1 & A2) ? B1 : ((A1 & ~A2) ? C1 : 1'b0));

endmodule
